using System.ComponentModel;
using System.Text.Json;
using ModelContextProtocol.Server;

/// <summary>
/// MCP tools that wrap the JSONPlaceholder REST API via constructor-injected HttpClient.
/// </summary>
[McpServerToolType]
public class ApiTools(IHttpClientFactory httpClientFactory, ILogger<ApiTools> logger)
{
    private static readonly JsonSerializerOptions s_jsonOptions = new() { WriteIndented = true };

    [McpServerTool, Description("Get a post by its numeric ID from the REST API.")]
    public async Task<string> GetPost(
        [Description("The post ID (1-100)")] int id,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching post {Id}", id);
        var client = httpClientFactory.CreateClient("api");
        var json = await client.GetStringAsync($"/posts/{id}", cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("List all posts, optionally filtered by user ID.")]
    public async Task<string> ListPosts(
        [Description("Filter by user ID (optional)")] int? userId = null,
        CancellationToken cancellationToken = default)
    {
        var client = httpClientFactory.CreateClient("api");
        var url = userId.HasValue ? $"/posts?userId={userId}" : "/posts";
        var json = await client.GetStringAsync(url, cancellationToken);
        return FormatJson(json);
    }

    [McpServerTool, Description("Get all comments for a specific post.")]
    public async Task<string> GetComments(
        [Description("The post ID to get comments for")] int postId,
        CancellationToken cancellationToken = default)
    {
        logger.LogInformation("Fetching comments for post {PostId}", postId);
        var client = httpClientFactory.CreateClient("api");
        var json = await client.GetStringAsync($"/posts/{postId}/comments", cancellationToken);
        return FormatJson(json);
    }

    private static string FormatJson(string json)
    {
        using var doc = JsonDocument.Parse(json);
        return JsonSerializer.Serialize(doc, s_jsonOptions);
    }
}

